        timeLimit: question.time_limit_seconds || 120,
        questionNumber: 1,
        totalQuestions: 10
      }
    });
  } catch (error) {
    await client.query('ROLLBACK');
    console.error('Error starting assessment:', error);
    res.status(500).json({ error: 'Failed to start assessment' });
  } finally {
